  1ŌåÆpackage handler
  2ŌåÆ
  3ŌåÆimport (
  4ŌåÆ	"encoding/csv"
  5ŌåÆ	"encoding/json"
  6ŌåÆ	"fmt"
  7ŌåÆ	"log/slog"
  8ŌåÆ	"net/http"
  9ŌåÆ	"strconv"
 10ŌåÆ	"strings"
 11ŌåÆ
 12ŌåÆ	"github.com/jackc/pgx/v5/pgxpool"
 13ŌåÆ
 14ŌåÆ	"github.com/ketang/kapow/api/internal/auth"
 15ŌåÆ	"github.com/ketang/kapow/api/internal/search"
 16ŌåÆ)
 17ŌåÆ
 18ŌåÆ// ExportCSV returns an HTTP handler that streams search results as a CSV file.
 19ŌåÆ// It reads filter, sort, and user-location parameters from the query string,
 20ŌåÆ// builds a search query capped at maxRows, and writes the results as CSV.
 21ŌåÆfunc ExportCSV(pool *pgxpool.Pool, reg *search.Registry, maxRows int) http.HandlerFunc {
 22ŌåÆ	return func(w http.ResponseWriter, r *http.Request) {
 23ŌåÆ		q := r.URL.Query()
 24ŌåÆ
 25ŌåÆ		// Parse filters from query param.
 26ŌåÆ		var filters []search.FilterInput
 27ŌåÆ		if filtersParam := q.Get("filters"); filtersParam != "" {
 28ŌåÆ			if err := json.Unmarshal([]byte(filtersParam), &filters); err != nil {
 29ŌåÆ				writeJSONError(w, http.StatusBadRequest,
 30ŌåÆ					fmt.Sprintf("handler: invalid filters JSON: %v", err))
 31ŌåÆ				return
 32ŌåÆ			}
 33ŌåÆ		}
 34ŌåÆ
 35ŌåÆ		req := search.SearchRequest{
 36ŌåÆ			Filters: filters,
 37ŌåÆ			Limit:   maxRows, // request the maximum; BuildExportQuery caps it
 38ŌåÆ		}
 39ŌåÆ
 40ŌåÆ		// Parse sort.
 41ŌåÆ		if sortParam := q.Get("sort"); sortParam != "" {
 42ŌåÆ			req.Sort = &search.SortInput{
 43ŌåÆ				Field:     sortParam,
 44ŌåÆ				Direction: search.SortDirectionAsc,
 45ŌåÆ			}
 46ŌåÆ			if dirParam := q.Get("sortDir"); dirParam == "DESC" {
 47ŌåÆ				req.Sort.Direction = search.SortDirectionDesc
 48ŌåÆ			}
 49ŌåÆ		}
 50ŌåÆ
 51ŌåÆ		// Parse user location.
 52ŌåÆ		latStr, lngStr := q.Get("userLat"), q.Get("userLng")
 53ŌåÆ		if latStr != "" && lngStr != "" {
 54ŌåÆ			lat, errLat := strconv.ParseFloat(latStr, 64)
 55ŌåÆ			lng, errLng := strconv.ParseFloat(lngStr, 64)
 56ŌåÆ			if errLat != nil || errLng != nil {
 57ŌåÆ				writeJSONError(w, http.StatusBadRequest, "handler: invalid userLat/userLng")
 58ŌåÆ				return
 59ŌåÆ			}
 60ŌåÆ			req.UserLocation = &search.UserLocation{
 61ŌåÆ				Latitude:  lat,
 62ŌåÆ				Longitude: lng,
 63ŌåÆ			}
 64ŌåÆ			if stateParam := q.Get("userState"); stateParam != "" {
 65ŌåÆ				req.UserLocation.State = stateParam
 66ŌåÆ			}
 67ŌåÆ		}
 68ŌåÆ
 69ŌåÆ		// Validate the request using the caller's real auth state.
 70ŌåÆ		authenticated := auth.GetClaims(r.Context()) != nil
 71ŌåÆ		if errs := search.ValidateRequest(reg, req, authenticated); len(errs) > 0 {
 72ŌåÆ			body, _ := json.Marshal(map[string]any{"errors": errs})
 73ŌåÆ			w.Header().Set("Content-Type", "application/json")
 74ŌåÆ			w.WriteHeader(http.StatusBadRequest)
 75ŌåÆ			_, _ = w.Write(body)
 76ŌåÆ			return
 77ŌåÆ		}
 78ŌåÆ
 79ŌåÆ		// Build and execute the export query.
 80ŌåÆ		sqlStr, args, err := search.BuildExportQuery(reg, req, maxRows)
 81ŌåÆ		if err != nil {
 82ŌåÆ			slog.ErrorContext(r.Context(), "handler: build export query", "error", err)
 83ŌåÆ			writeJSONError(w, http.StatusInternalServerError, "handler: failed to build query")
 84ŌåÆ			return
 85ŌåÆ		}
 86ŌåÆ
 87ŌåÆ		rows, err := pool.Query(r.Context(), sqlStr, args...)
 88ŌåÆ		if err != nil {
 89ŌåÆ			slog.ErrorContext(r.Context(), "handler: export query", "error", err)
 90ŌåÆ			writeJSONError(w, http.StatusInternalServerError, "handler: query failed")
 91ŌåÆ			return
 92ŌåÆ		}
 93ŌåÆ		defer rows.Close()
 94ŌåÆ
 95ŌåÆ		// Get exportable field descriptors for CSV columns.
 96ŌåÆ		descriptors := reg.ExportableDescriptors()
 97ŌåÆ
 98ŌåÆ		// Build CSV header row from descriptor labels.
 99ŌåÆ		header := make([]string, len(descriptors))
100ŌåÆ		for i, d := range descriptors {
101ŌåÆ			header[i] = d.Label
102ŌåÆ		}
103ŌåÆ
104ŌåÆ		// Scan all rows before writing ŌĆö allows error handling before
105ŌåÆ		// committing to 200 + CSV headers.
106ŌåÆ		type rowData struct {
107ŌåÆ			unitID          string
108ŌåÆ			institutionName string
109ŌåÆ			city            string
110ŌåÆ			state           string
111ŌåÆ			data            json.RawMessage
112ŌåÆ		}
113ŌåÆ		var rowResults []rowData
114ŌåÆ
115ŌåÆ		for rows.Next() {
116ŌåÆ			var (
117ŌåÆ				unitID, instName, city, state string
118ŌåÆ				lat, lng, distance            *float64
119ŌåÆ				myPrice                       *int
120ŌåÆ				data                          json.RawMessage
121ŌåÆ				blendScore                    *float64 // column 10: unused in export but must be scanned
122ŌåÆ			)
123ŌåÆ			if err := rows.Scan(&unitID, &instName, &city, &state,
124ŌåÆ				&lat, &lng, &distance, &myPrice, &data, &blendScore); err != nil {
125ŌåÆ				slog.ErrorContext(r.Context(), "handler: scan export row", "error", err)
126ŌåÆ				writeJSONError(w, http.StatusInternalServerError, "handler: scan failed")
127ŌåÆ				return
128ŌåÆ			}
129ŌåÆ			rowResults = append(rowResults, rowData{
130ŌåÆ				unitID:          unitID,
131ŌåÆ				institutionName: instName,
132ŌåÆ				city:            city,
133ŌåÆ				state:           state,
134ŌåÆ				data:            data,
135ŌåÆ			})
136ŌåÆ		}
137ŌåÆ		if err := rows.Err(); err != nil {
138ŌåÆ			slog.ErrorContext(r.Context(), "handler: export rows iteration", "error", err)
139ŌåÆ			writeJSONError(w, http.StatusInternalServerError, "handler: query iteration failed")
140ŌåÆ			return
141ŌåÆ		}
142ŌåÆ
143ŌåÆ		// Write CSV response.
144ŌåÆ		w.Header().Set("Content-Type", "text/csv; charset=utf-8")
145ŌåÆ		w.Header().Set("Content-Disposition", `attachment; filename="colleges-export.csv"`)
146ŌåÆ
147ŌåÆ		cw := csv.NewWriter(w)
148ŌåÆ		if err := cw.Write(header); err != nil {
149ŌåÆ			slog.ErrorContext(r.Context(), "handler: write CSV header", "error", err)
150ŌåÆ			return
151ŌåÆ		}
152ŌåÆ
153ŌåÆ		record := make([]string, len(descriptors))
154ŌåÆ		for _, row := range rowResults {
155ŌåÆ			for i, d := range descriptors {
156ŌåÆ				record[i] = extractCoreOrJSONB(d, row.unitID, row.institutionName, row.city, row.state, row.data)
157ŌåÆ			}
158ŌåÆ			if err := cw.Write(record); err != nil {
159ŌåÆ				slog.ErrorContext(r.Context(), "handler: write CSV row", "error", err)
160ŌåÆ				return
161ŌåÆ			}
162ŌåÆ		}
163ŌåÆ		// Append data sources citation section.
164ŌåÆ		writeCitationSection(cw, descriptors)
165ŌåÆ
166ŌåÆ		cw.Flush()
167ŌåÆ		if err := cw.Error(); err != nil {
168ŌåÆ			slog.ErrorContext(r.Context(), "handler: flush CSV", "error", err)
169ŌåÆ		}
170ŌåÆ	}
171ŌåÆ}
172ŌåÆ
173ŌåÆ// writeCitationSection appends a "Data Sources" section to the CSV listing each
174ŌåÆ// unique data source referenced by the exported fields.
175ŌåÆfunc writeCitationSection(cw *csv.Writer, descriptors []search.FieldDescriptor) {
176ŌåÆ	// Build IDŌåÆDataSource lookup.
177ŌåÆ	allSources := search.AllDataSources()
178ŌåÆ	sourceByID := make(map[string]search.DataSource, len(allSources))
179ŌåÆ	for _, ds := range allSources {
180ŌåÆ		sourceByID[ds.ID] = ds
181ŌåÆ	}
182ŌåÆ
183ŌåÆ	// Collect unique sources in stable order (first-seen among descriptors).
184ŌåÆ	seen := make(map[string]bool)
185ŌåÆ	var sources []search.DataSource
186ŌåÆ	for _, d := range descriptors {
187ŌåÆ		if d.DataSourceID == "" || seen[d.DataSourceID] {
188ŌåÆ			continue
189ŌåÆ		}
190ŌåÆ		seen[d.DataSourceID] = true
191ŌåÆ		if ds, ok := sourceByID[d.DataSourceID]; ok {
192ŌåÆ			sources = append(sources, ds)
193ŌåÆ		}
194ŌåÆ	}
195ŌåÆ	if len(sources) == 0 {
196ŌåÆ		return
197ŌåÆ	}
198ŌåÆ
199ŌåÆ	_ = cw.Write([]string{}) // blank separator row
200ŌåÆ	_ = cw.Write([]string{"Data Sources"})
201ŌåÆ	_ = cw.Write([]string{"Source", "Dataset", "URL"})
202ŌåÆ	for _, ds := range sources {
203ŌåÆ		_ = cw.Write([]string{ds.Name, ds.Dataset, ds.URL})
204ŌåÆ	}
205ŌåÆ}
206ŌåÆ
207ŌåÆ// extractCoreOrJSONB returns the CSV cell value for a descriptor.
208ŌåÆ// Core fields (name, city, state, unit_id) are extracted from scanned columns;
209ŌåÆ// all others are extracted from the data JSONB blob via OutputKey.
210ŌåÆfunc extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
211ŌåÆ	switch d.Name {
212ŌåÆ	case "name":
213ŌåÆ		return instName
214ŌåÆ	case "city":
215ŌåÆ		return city
216ŌåÆ	case "state":
217ŌåÆ		return state
218ŌåÆ	case "unit_id":
219ŌåÆ		return unitID
220ŌåÆ	default:
221ŌåÆ		if d.OutputKey == "" {
222ŌåÆ			return ""
223ŌåÆ		}
224ŌåÆ		raw := extractJSONBValue(data, d.OutputKey)
225ŌåÆ		if raw != "" && len(d.Options) > 0 {
226ŌåÆ			return d.LabelForCode(raw)
227ŌåÆ		}
228ŌåÆ		return raw
229ŌåÆ	}
230ŌåÆ}
231ŌåÆ
232ŌåÆ// extractJSONBValue navigates a dot-separated path into a JSON blob and
233ŌåÆ// returns the value as a string. Returns "" for nil, missing, or unparseable.
234ŌåÆfunc extractJSONBValue(data json.RawMessage, dotPath string) string {
235ŌåÆ	if len(data) == 0 {
236ŌåÆ		return ""
237ŌåÆ	}
238ŌåÆ	parts := strings.Split(dotPath, ".")
239ŌåÆ	var current any
240ŌåÆ	if err := json.Unmarshal(data, &current); err != nil {
241ŌåÆ		return ""
242ŌåÆ	}
243ŌåÆ	for _, part := range parts {
244ŌåÆ		m, ok := current.(map[string]any)
245ŌåÆ		if !ok {
246ŌåÆ			return ""
247ŌåÆ		}
248ŌåÆ		current, ok = m[part]
249ŌåÆ		if !ok {
250ŌåÆ			return ""
251ŌåÆ		}
252ŌåÆ	}
253ŌåÆ	if current == nil {
254ŌåÆ		return ""
255ŌåÆ	}
256ŌåÆ	return fmt.Sprintf("%v", current)
257ŌåÆ}
258ŌåÆ
259ŌåÆ// writeJSONError writes a JSON error response with the given status code and message.
260ŌåÆfunc writeJSONError(w http.ResponseWriter, status int, message string) {
261ŌåÆ	w.Header().Set("Content-Type", "application/json")
262ŌåÆ	w.WriteHeader(status)
263ŌåÆ	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
264ŌåÆ}
