  1ŌåÆpackage search
  2ŌåÆ
  3ŌåÆimport (
  4ŌåÆ	"encoding/json"
  5ŌåÆ	"fmt"
  6ŌåÆ)
  7ŌåÆ
  8ŌåÆ// ValidationError describes a single validation failure.
  9ŌåÆtype ValidationError struct {
 10ŌåÆ	Field   string `json:"field"`
 11ŌåÆ	Message string `json:"message"`
 12ŌåÆ}
 13ŌåÆ
 14ŌåÆ// Unexported interfaces let the validator access concrete-type metadata without
 15ŌåÆ// widening the public Field interface.
 16ŌåÆtype hasEnumOptions interface{ enumOptions() []EnumOption }
 17ŌåÆtype hasHardBounds interface{ hardBounds() (min, max *float64) }
 18ŌåÆtype hasMaxRadius interface{ maxRadiusKm() float64 }
 19ŌåÆ
 20ŌåÆ// ValidateRequest validates a SearchRequest against the registry.
 21ŌåÆ// All errors are collected (no short-circuit) and returned as a slice.
 22ŌåÆ// A nil/empty slice means the request is valid.
 23ŌåÆ//
 24ŌåÆ// The authenticated flag controls access to RESTRICTED fields: when false,
 25ŌåÆ// any filter on a RESTRICTED-searchability field produces a validation error.
 26ŌåÆfunc ValidateRequest(reg *Registry, req SearchRequest, authenticated bool) []ValidationError {
 27ŌåÆ	var errs []ValidationError
 28ŌåÆ
 29ŌåÆ	for _, fi := range req.Filters {
 30ŌåÆ		field, ok := reg.Lookup(fi.Field)
 31ŌåÆ		if !ok {
 32ŌåÆ			errs = append(errs, ValidationError{Field: fi.Field, Message: "unknown field"})
 33ŌåÆ			continue
 34ŌåÆ		}
 35ŌåÆ
 36ŌåÆ		if !IsFieldSearchable(field.Descriptor(), authenticated) {
 37ŌåÆ			errs = append(errs, ValidationError{Field: fi.Field, Message: "field requires authentication"})
 38ŌåÆ			continue
 39ŌåÆ		}
 40ŌåÆ
 41ŌåÆ		switch field.Kind() {
 42ŌåÆ		case KindFullText:
 43ŌåÆ			var f FullTextFilter
 44ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
 45ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 46ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 47ŌåÆ				continue
 48ŌåÆ			}
 49ŌåÆ			if len(f.Query) > 512 {
 50ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 51ŌåÆ					Message: "value exceeds maximum length of 512 characters"})
 52ŌåÆ			}
 53ŌåÆ
 54ŌåÆ		case KindSubstring:
 55ŌåÆ			var f SubstringFilter
 56ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
 57ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 58ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 59ŌåÆ				continue
 60ŌåÆ			}
 61ŌåÆ			if len(f.Value) > 512 {
 62ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 63ŌåÆ					Message: "value exceeds maximum length of 512 characters"})
 64ŌåÆ			}
 65ŌåÆ
 66ŌåÆ		case KindExactString:
 67ŌåÆ			var f ExactStringFilter
 68ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
 69ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 70ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 71ŌåÆ				continue
 72ŌåÆ			}
 73ŌåÆ			if len(f.Value) > 512 {
 74ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 75ŌåÆ					Message: "value exceeds maximum length of 512 characters"})
 76ŌåÆ			}
 77ŌåÆ
 78ŌåÆ		case KindExactNumeric:
 79ŌåÆ			var f ExactNumericFilter
 80ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
 81ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 82ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 83ŌåÆ			}
 84ŌåÆ
 85ŌåÆ		case KindNumericRange:
 86ŌåÆ			var f NumericRangeFilter
 87ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
 88ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 89ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
 90ŌåÆ				continue
 91ŌåÆ			}
 92ŌåÆ			if f.Min == nil && f.Max == nil {
 93ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
 94ŌåÆ					Message: "at least one of min or max is required"})
 95ŌåÆ				break
 96ŌåÆ			}
 97ŌåÆ			if hb, ok := field.(hasHardBounds); ok {
 98ŌåÆ				hardMin, hardMax := hb.hardBounds()
 99ŌåÆ				if f.Min != nil && hardMin != nil && *f.Min < *hardMin {
100ŌåÆ					errs = append(errs, ValidationError{Field: fi.Field,
101ŌåÆ						Message: "value out of allowed range"})
102ŌåÆ				}
103ŌåÆ				if f.Max != nil && hardMax != nil && *f.Max > *hardMax {
104ŌåÆ					errs = append(errs, ValidationError{Field: fi.Field,
105ŌåÆ						Message: "value out of allowed range"})
106ŌåÆ				}
107ŌåÆ			}
108ŌåÆ
109ŌåÆ		case KindSingleEnum:
110ŌåÆ			var f SingleEnumFilter
111ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
112ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
113ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
114ŌåÆ				continue
115ŌåÆ			}
116ŌåÆ			if eo, ok := field.(hasEnumOptions); ok {
117ŌåÆ				opts := eo.enumOptions()
118ŌåÆ				if opts != nil && !containsOption(opts, f.Value) {
119ŌåÆ					errs = append(errs, ValidationError{Field: fi.Field,
120ŌåÆ						Message: fmt.Sprintf("value %q not in allowed options", f.Value)})
121ŌåÆ				}
122ŌåÆ			}
123ŌåÆ
124ŌåÆ		case KindMultiEnum:
125ŌåÆ			var f MultiEnumFilter
126ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
127ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
128ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
129ŌåÆ				continue
130ŌåÆ			}
131ŌåÆ			if len(f.Values) == 0 {
132ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
133ŌåÆ					Message: "at least one value required"})
134ŌåÆ				break
135ŌåÆ			}
136ŌåÆ			if eo, ok := field.(hasEnumOptions); ok {
137ŌåÆ				opts := eo.enumOptions()
138ŌåÆ				if opts != nil {
139ŌåÆ					for _, v := range f.Values {
140ŌåÆ						if !containsOption(opts, v) {
141ŌåÆ							errs = append(errs, ValidationError{Field: fi.Field,
142ŌåÆ								Message: fmt.Sprintf("value %q not in allowed options", v)})
143ŌåÆ						}
144ŌåÆ					}
145ŌåÆ				}
146ŌåÆ			}
147ŌåÆ
148ŌåÆ		case KindGeo:
149ŌåÆ			var f GeoFilterInput
150ŌåÆ			if err := json.Unmarshal(fi.Value, &f); err != nil {
151ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
152ŌåÆ					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
153ŌåÆ				continue
154ŌåÆ			}
155ŌåÆ			switch f.Kind {
156ŌåÆ			case GeoFilterKindRadius:
157ŌåÆ				if f.Radius == nil {
158ŌåÆ					errs = append(errs, ValidationError{Field: fi.Field,
159ŌåÆ						Message: "radius filter requires radius object"})
160ŌåÆ				} else {
161ŌåÆ					if f.Radius.RadiusKm <= 0 {
162ŌåÆ						errs = append(errs, ValidationError{Field: fi.Field,
163ŌåÆ							Message: "radius must be positive"})
164ŌåÆ					}
165ŌåÆ					if mr, ok := field.(hasMaxRadius); ok {
166ŌåÆ						if f.Radius.RadiusKm > mr.maxRadiusKm() {
167ŌåÆ							errs = append(errs, ValidationError{Field: fi.Field,
168ŌåÆ								Message: fmt.Sprintf("radius exceeds maximum of %g km", mr.maxRadiusKm())})
169ŌåÆ						}
170ŌåÆ					}
171ŌåÆ				}
172ŌåÆ			case GeoFilterKindBBox:
173ŌåÆ				if f.BBox == nil {
174ŌåÆ					errs = append(errs, ValidationError{Field: fi.Field,
175ŌåÆ						Message: "bbox filter requires bbox object"})
176ŌåÆ				}
177ŌåÆ			default:
178ŌåÆ				errs = append(errs, ValidationError{Field: fi.Field,
179ŌåÆ					Message: fmt.Sprintf("unknown geo filter kind: %q", f.Kind)})
180ŌåÆ			}
181ŌåÆ		}
182ŌåÆ	}
183ŌåÆ
184ŌåÆ	// Pagination checks use sentinel field names.
185ŌåÆ	if req.Limit > MaxLimit {
186ŌåÆ		errs = append(errs, ValidationError{Field: "_limit",
187ŌåÆ			Message: fmt.Sprintf("limit exceeds maximum of %d", MaxLimit)})
188ŌåÆ	}
189ŌåÆ	if req.Offset < 0 {
190ŌåÆ		errs = append(errs, ValidationError{Field: "_offset",
191ŌåÆ			Message: "offset must be non-negative"})
192ŌåÆ	}
193ŌåÆ
194ŌåÆ	// UserLocation validation.
195ŌåÆ	if loc := req.UserLocation; loc != nil {
